"use strict";(globalThis.webpackChunkdocusaurus_resource=globalThis.webpackChunkdocusaurus_resource||[]).push([[9306],{5554:i=>{i.exports=JSON.parse('{"tag":{"label":"type/guide","permalink":"/accessibility-hub/docs/tags/type-guide","allTagsPath":"/accessibility-hub/docs/tags","count":24,"items":[{"id":"hot-topics/accessibility-audit","title":"Accessibility Audit","description":"Accessibility Audit covers the process and tools for evaluating digital content for accessibility compliance. This page will be expanded and curated with more detailed guidance and resources in the future.","permalink":"/accessibility-hub/docs/hot-topics/accessibility-audit"},{"id":"hot-topics/accessibility-testing","title":"Accessibility Testing","description":"Accessibility Testing covers the tools, methods, and best practices for evaluating digital content for accessibility. This page will be expanded and curated with more detailed guidance and resources in the future.","permalink":"/accessibility-hub/docs/hot-topics/accessibility-testing"},{"id":"for-developers/accessible-web-dev-checklist","title":"Accessible Web Development Checklist","description":"A comprehensive checklist based on WCAG 2.1 Level AA and best practices from W3C, WebAIM, and Section508.gov.","permalink":"/accessibility-hub/docs/for-developers/accessible-web-dev-checklist"},{"id":"hot-topics/alt-text-ai","title":"Alt Text AI","description":"Alt Text AI is a tool or concept related to generating or improving alternative text for images using artificial intelligence. This page will be expanded and curated with more detailed content in the future to help users understand and leverage AI for accessible image descriptions.","permalink":"/accessibility-hub/docs/hot-topics/alt-text-ai"},{"id":"for-users/by-disability-type/mobility/aphasia-communication-quickstart","title":"Aphasia Communication Quick Start for Caregivers","description":"Stroke Communication Support Guide for Caregivers, for a person who cannot speak, cannot read or write, prefers sound, and can use a touchscreen or gestures.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/mobility/aphasia-communication-quickstart"},{"id":"hot-topics/aria-roles","title":"ARIA Roles","description":"ARIA Roles define the purpose of elements in web content for assistive technologies. More curated content and examples will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/aria-roles"},{"id":"hot-topics/bug-bounty","title":"Bug Bounty","description":"Bug Bounty programs encourage the discovery and reporting of accessibility issues. More curated content and examples will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/bug-bounty"},{"id":"for-users/by-disability-type/speech-language/stroke-caregiver-guide","title":"Caregiver Guide for Post-Stroke Communication","description":"Supporting a loved one after stroke involves patience, creativity, and knowledge of communication strategies.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/speech-language/stroke-caregiver-guide"},{"id":"hot-topics/color-contrast","title":"Color Contrast","description":"Color Contrast is essential for readability and accessibility, especially for users with visual impairments. This page will be expanded and curated with more information and best practices in the future.","permalink":"/accessibility-hub/docs/hot-topics/color-contrast"},{"id":"hot-topics/dyslexia-support","title":"Dyslexia Support","description":"Dyslexia Support covers tools and strategies to assist individuals with dyslexia. This page will be expanded and curated with more resources and best practices in the future.","permalink":"/accessibility-hub/docs/hot-topics/dyslexia-support"},{"id":"hot-topics/github-access-tools","title":"GitHub Access Tools","description":"GitHub Access Tools are resources and utilities to improve accessibility for developers and users on GitHub. This page will be expanded and curated with more information in the future.","permalink":"/accessibility-hub/docs/hot-topics/github-access-tools"},{"id":"hot-topics/inclusive-design","title":"Inclusive Design","description":"Inclusive Design is about creating products and experiences that are accessible to as many people as possible. This page will be expanded and curated with more resources and examples in the future.","permalink":"/accessibility-hub/docs/hot-topics/inclusive-design"},{"id":"hot-topics/langchain4j-tools","title":"LangChain4J Tools","description":"LangChain4J Tools are resources for integrating language models and AI into Java applications. This page will be expanded and curated with more information and examples in the future.","permalink":"/accessibility-hub/docs/hot-topics/langchain4j-tools"},{"id":"community-contributions/FRONTMATTER_GUIDE","title":"Metadata for Resources (Frontmatter) guide","description":"Every file must include a frontmatter section (YAML metadata) to classify and describe the resource. This helps us organize the hub and ensures your contribution integrates seamlessly into our systems.","permalink":"/accessibility-hub/docs/community-contributions/FRONTMATTER_GUIDE"},{"id":"hot-topics/nlp-assist","title":"NLP Assist","description":"NLP Assist refers to the use of Natural Language Processing to support accessibility and user interaction. More curated content and examples will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/nlp-assist"},{"id":"hot-topics/otter-ai","title":"Otter.ai","description":"Otter.ai is a tool for real-time transcription and captioning. More curated content and practical guidance will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/otter-ai"},{"id":"resources/learning-paths/quickstart-guide","title":"Quickstart Guide with FOSS","description":"This plan is designed to get you hands-on with core accessibility concepts in one week, using freely available, and wherever possible, open-source tools.","permalink":"/accessibility-hub/docs/resources/learning-paths/quickstart-guide"},{"id":"hot-topics/real-time-captions","title":"Real-time Captions","description":"Real-time Captions provide instant text transcriptions of spoken content, improving accessibility for users who are deaf or hard of hearing. This page will be expanded and curated with more information and resources in the future.","permalink":"/accessibility-hub/docs/hot-topics/real-time-captions"},{"id":"hot-topics/seeing-ai","title":"Seeing AI","description":"Seeing AI is a Microsoft app that narrates the world for people with visual impairments. More curated content and practical guidance will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/seeing-ai"},{"id":"hot-topics/smart-homes","title":"Smart Homes","description":"Smart Homes leverage technology to improve accessibility and independence for people with disabilities. More curated content and practical guidance will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/smart-homes"},{"id":"hot-topics/springai-assistive","title":"SpringAI Assistive","description":"SpringAI Assistive is a framework or tool for integrating AI-powered accessibility features. More curated content and examples will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/springai-assistive"},{"id":"for-users/by-disability-type/speech-language/stroke-communication-checklist","title":"Stroke Communication Needs Checklist","description":"This checklist helps caregivers and professionals assess the communication abilities of individuals recovering from stroke. It supports the selection of appropriate AAC tools and therapy strategies.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/speech-language/stroke-communication-checklist"},{"id":"community-contributions/TOPICS_GUIDE","title":"Topics Guide","description":"1. List of Existing Keywords/Topics","permalink":"/accessibility-hub/docs/community-contributions/TOPICS_GUIDE"},{"id":"hot-topics/voice-navigation","title":"Voice Navigation","description":"Voice Navigation explores the use of voice commands and speech recognition to navigate digital interfaces. More content will be added and curated in the future to provide comprehensive guidance and resources on this topic.","permalink":"/accessibility-hub/docs/hot-topics/voice-navigation"}],"unlisted":false}}')}}]);